import{_ as t,o as e,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"常见问题（FAQ）","description":"","frontmatter":{},"headers":[],"relativePath":"guides/faq.md","filePath":"zh/guides/faq.md","lastUpdated":1775394001000}'),i={name:"guides/faq.md"};function o(s,a,h,l,n,q){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="常见问题-faq" tabindex="-1">常见问题（FAQ） <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题（FAQ）&quot;">​</a></h1><h2 id="基础问题" tabindex="-1">基础问题 <a class="header-anchor" href="#基础问题" aria-label="Permalink to &quot;基础问题&quot;">​</a></h2><h3 id="q-忘却前夜是什么类型的游戏" tabindex="-1">Q: 忘却前夜是什么类型的游戏？ <a class="header-anchor" href="#q-忘却前夜是什么类型的游戏" aria-label="Permalink to &quot;Q: 忘却前夜是什么类型的游戏？&quot;">​</a></h3><p>A: 忘却前夜（Morimens）是一款以克苏鲁神话为世界观的 <strong>Roguelite 卡牌构筑</strong> 手游。由 B.I.A.V. Studio（灵犀互娱旗下）开发，结合了 CCG（集换式卡牌）、Roguelite、视觉小说和回合制策略等要素。</p><h3 id="q-游戏有哪些平台" tabindex="-1">Q: 游戏有哪些平台？ <a class="header-anchor" href="#q-游戏有哪些平台" aria-label="Permalink to &quot;Q: 游戏有哪些平台？&quot;">​</a></h3><p>A: iOS、Android 和 PC（Steam），免费游玩。</p><h3 id="q-各版本有什么区别" tabindex="-1">Q: 各版本有什么区别？ <a class="header-anchor" href="#q-各版本有什么区别" aria-label="Permalink to &quot;Q: 各版本有什么区别？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>版本</th><th>地区</th><th>发行商</th><th>特点</th></tr></thead><tbody><tr><td><span class="server-badge server-cn">国服</span></td><td>中国大陆</td><td>灵犀互娱</td><td>内容最领先</td></tr><tr><td><span class="server-badge server-global">国际服</span></td><td>全球</td><td>B.I.A.V. Studio</td><td>支持简繁中、英、日、韩、泰、俄、欧洲语言</td></tr><tr><td><span class="server-badge server-jp">日服</span></td><td>日本</td><td>AltPlus Inc.</td><td><strong>数值大幅调整</strong>，独立 Steam 版本</td></tr><tr><td><span class="server-badge server-tw">台服</span></td><td>台湾</td><td>Sialia Games</td><td>繁体中文</td></tr><tr><td>港澳新马服</td><td>东南亚</td><td>Qookka Games</td><td>繁中/英文</td></tr></tbody></table><h3 id="q-日服和其他服有什么不同" tabindex="-1">Q: 日服和其他服有什么不同？ <a class="header-anchor" href="#q-日服和其他服有什么不同" aria-label="Permalink to &quot;Q: 日服和其他服有什么不同？&quot;">​</a></h3><p>A: 日服版本的唤醒体和装备性能经过了大幅度的重新平衡调整，与国服/国际服存在较大差异。日服也有独立的 Steam 应用。</p><h2 id="战斗相关" tabindex="-1">战斗相关 <a class="header-anchor" href="#战斗相关" aria-label="Permalink to &quot;战斗相关&quot;">​</a></h2><h3 id="q-算力-arithmetica-每回合多少" tabindex="-1">Q: 算力（Arithmetica）每回合多少？ <a class="header-anchor" href="#q-算力-arithmetica-每回合多少" aria-label="Permalink to &quot;Q: 算力（Arithmetica）每回合多少？&quot;">​</a></h3><p>A: 每回合基础 5 点算力。</p><h3 id="q-狂气爆发需要多少狂气" tabindex="-1">Q: 狂气爆发需要多少狂气？ <a class="header-anchor" href="#q-狂气爆发需要多少狂气" aria-label="Permalink to &quot;Q: 狂气爆发需要多少狂气？&quot;">​</a></h3><p>A: 狂气积累至 100 点触发狂气爆发，不消耗算力。</p><h3 id="q-银钥-钥令怎么用" tabindex="-1">Q: 银钥/钥令怎么用？ <a class="header-anchor" href="#q-银钥-钥令怎么用" aria-label="Permalink to &quot;Q: 银钥/钥令怎么用？&quot;">​</a></h3><p>A: 银钥能量积累至 1000 点后可发动已装备的钥令。钥令在组队阶段装备。混沌界域可加速积累。</p><h2 id="抽卡相关" tabindex="-1">抽卡相关 <a class="header-anchor" href="#抽卡相关" aria-label="Permalink to &quot;抽卡相关&quot;">​</a></h2><h3 id="q-ssr-概率和保底" tabindex="-1">Q: SSR 概率和保底？ <a class="header-anchor" href="#q-ssr-概率和保底" aria-label="Permalink to &quot;Q: SSR 概率和保底？&quot;">​</a></h3><p>A: SSR 基础概率 <strong>3%</strong>，<strong>30 抽</strong> 硬保底。有大保底机制保证UP角色。</p><h3 id="q-游戏停服了怎么办" tabindex="-1">Q: 游戏停服了怎么办？ <a class="header-anchor" href="#q-游戏停服了怎么办" aria-label="Permalink to &quot;Q: 游戏停服了怎么办？&quot;">​</a></h3><p>A: 开发商已承诺如果游戏停运，将把游戏转化为有完整结局的单机体验。</p><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><h3 id="q-如何为wiki贡献内容" tabindex="-1">Q: 如何为Wiki贡献内容？ <a class="header-anchor" href="#q-如何为wiki贡献内容" aria-label="Permalink to &quot;Q: 如何为Wiki贡献内容？&quot;">​</a></h3><p>A: 可通过以下方式贡献：</p><ol><li>在 GitHub 上提交 Pull Request</li><li>在 Issue 中反馈错误信息</li></ol>',26)])])}const b=t(i,[["render",o]]);export{u as __pageData,b as default};
